import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjInputTime } from "./OjInputTime";
export { OjInputTime };

/**
 * Create an instance of [[OjInputTime]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojInputTime(driver, By.id('my-oj-input-time'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojInputTime(driver: DriverLike, by: By): Promise<OjInputTime> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjInputTime
  if (!(webEl instanceof OjInputTime)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-input-time>`);
  }
  return webEl;
}

register("oj-input-time", OjInputTime);
